// Filter for high impact events in next 4 hours
// TradingEconomics format: {Calendar: [{Country, Event, Date, Impact, Currency, ...}]}
const raw = $input.first().json;
const events = Array.isArray(raw) ? raw : (raw.Calendar || []);
const now = new Date();
const cutoff = new Date(now.getTime() + 4 * 60 * 60 * 1000);

// Map TradingEconomics fields to our format
const mappedEvents = events.map(e => ({
  datetime: e.Date,
  event: e.Event,
  impact: e.Impact || 'medium',
  currency: e.Country === 'United States' ? 'USD' : (e.Country === 'Euro Zone' ? 'EUR' : e.Currency || ''),
  previous: e.Previous,
  forecast: e.Forecast,
  actual: e.Actual,
}));

const highImpactEvents = mappedEvents.filter(e => {
  const eventTime = new Date(e.datetime);
  const isHigh = e.impact && e.impact.toLowerCase().includes('high');
  return isHigh && eventTime >= now && eventTime <= cutoff;
});

highImpactEvents.sort((a, b) => new Date(a.datetime) - new Date(b.datetime));

const soonEvents = mappedEvents.filter(e => {
  const eventTime = new Date(e.datetime);
  const diff = eventTime - now;
  const isHigh = e.impact && e.impact.toLowerCase().includes('high');
  return diff > 0 && diff <= 30 * 60 * 1000 && isHigh;
});

return {
  json: {
    highImpactEvents: highImpactEvents,
    soonEvents: soonEvents,
    blockActive: soonEvents.length > 0,
    eventCount: highImpactEvents.length,
    soonCount: soonEvents.length,
    nextEvent: highImpactEvents[0] || null,
    currentTime: now.toISOString()
  }
};

// Activate trade block and send alert
const data = $input.first().json;
const soonEvents = data.soonEvents;
const nextEvent = soonEvents[0];

const affectedPairs = {
  'USD': ['EURUSD', 'GBPUSD', 'USDCAD', 'USDJPY', 'AUDUSD', 'USDCHF'],
  'EUR': ['EURUSD', 'EURGBP', 'EURJPY', 'EURAUD', 'EURCAD'],
  'GBP': ['GBPUSD', 'EURGBP', 'GBPJPY', 'GBPAUD'],
  'JPY': ['USDJPY', 'EURJPY', 'GBPJPY'],
  'AUD': ['AUDUSD', 'AUDJPY', 'EURAUD'],
  'CAD': ['USDCAD', 'EURCAD'],
  'CHF': ['USDCHF', 'EURCHF'],
  'NZD': ['NZDUSD', 'AUDNZD']
};

const affectedCurrencies = [...new Set(soonEvents.map(e => e.currency).filter(c => c))];
const pairsToBlock = [...new Set(affectedCurrencies.flatMap(c => affectedCurrencies.flatMap(d => affectedCurrencies.length ? (affectedPairs[c] || []).filter(p => affectedPairs[d] && affectedPairs[d].includes(p)) : []))];

return {
  json: {
    action: 'ACTIVATE_BLOCK',
    reason: 'HIGH_IMPACT_EVENT',
    eventName: nextEvent.event,
    currency: nextEvent.currency,
    impact: nextEvent.impact,
    time: nextEvent.datetime,
    minutesUntil: Math.round((new Date(nextEvent.datetime) - new Date(data.currentTime)) / (60 * 1000)),
    affectedCurrencies: affectedCurrencies,
    pairsToBlock: [...new Set(pairsToBlock)],
    allEvents: soonEvents,
    blockDuration: 45, // 30 min before + 15 min after
    timestamp: new Date().toISOString()
  }
};

// Build Telegram alert message
const block = $input.first().json;
const eventList = block.allEvents.map(e => `• *${e.event}* (${e.currency}) — ${e.datetime}`).join('\n');

const pairsList = block.pairsToBlock.length > 0 ? `\n*Affected Pairs:* ${block.pairsToBlock.join(', ')}` : '';

return {
  json: {
    message: `⚠️ *TRADE BLOCK ACTIVATED*\n\n*High-impact event in ${block.minutesUntil} minutes:*\n${eventList}\n\n*Duration:* ${block.blockDuration} minutes (30 before + 15 after)${pairsList}\n\n🔴 *All automated execution BLOCKED during window*\n🕐 ${block.timestamp}`
  }
};

// Send upcoming events info
const data = $input.first().json;
const upcoming = data.highImpactEvents;

const eventList = upcoming.slice(0, 5).map(e => {
  const eventTime = new Date(e.datetime);
  const now = new Date();
  const hoursUntil = Math.round((eventTime - now) / (60 * 60 * 1000) * 10) / 10;
  return `• *${e.event}* (${e.currency}) — ${hoursUntil}h`;
}).join('\n');

return {
  json: {
    message: `📅 *Economic Calendar Preview*\n\n*${upcoming.length} high-impact events in next 4 hours:*\n${eventList}\n\nCurrent block status: ${data.blockActive ? '🔴 ACTIVE' : '🟢 CLEAR'}`
  }
};

// Check existing positions in affected pairs
const block = $input.first().json;
const url = `{{ $env.CTRADER_API_URL }}/v2/positions`;

return block;

// Check if any positions are in affected pairs
const positions = $input.first().json.positions || [];
const blockData = $('Prepare Position Check').first().json;
const affectedPairs = blockData.pairsToBlock || [];

const exposedPositions = positions.filter(p => affectedPairs.includes(p.symbol));

if (exposedPositions.length === 0) {
  return [];
}

return exposedPositions.map(p => ({
  json: {
    positionId: p.positionId,
    symbol: p.symbol,
    direction: p.direction,
    volume: p.volume,
    unrealizedPnLPips: p.unrealizedPnLPips,
    entryPrice: p.entryPrice,
    eventName: blockData.eventName
  }
}));

// Format position alert for affected pairs
const positions = $input.all().map(n => n.json);
const blockData = $('Prepare Position Check').first().json;

const posList = positions.map(p => 
  `• #${p.positionId}: ${p.direction} ${p.volume} lots ${p.symbol} (${p.unrealizedPnLPips} pips)`
).join('\n');

return {
  json: {
    message: `⚠️ *EXPOSED POSITIONS ALERT*\n\n*High-impact event approaching:* ${blockData.eventName}\n*Time:* ${blockData.time}\n\n*Positions in affected pairs:*\n${posList}\n\n💡 Consider reducing risk or manually monitoring these trades during the event window.`
  }
};

// Log that no action was needed
return {
  json: {
    status: 'CLEAR',
    timestamp: new Date().toISOString(),
    message: 'No high-impact events in next 4 hours. Trading window clear.'
  }
};
